/**
 * @suppress
 */
public object FfiConverterTypeUmbrellaClientHandle: FfiConverter<UmbrellaClientHandle, Long> {
    override fun lower(value: UmbrellaClientHandle): Long {
        return value.uniffiCloneHandle()
    }

    override fun lift(value: Long): UmbrellaClientHandle {
        return UmbrellaClientHandle(UniffiWithHandle, value)
    }

    override fun read(buf: ByteBuffer): UmbrellaClientHandle {
        return lift(buf.getLong())
    }

    override fun allocationSize(value: UmbrellaClientHandle) = 8UL

    override fun write(value: UmbrellaClientHandle, buf: ByteBuffer) {
        buf.putLong(lower(value))
    }
}



