 */
public object FfiConverterTypeCallStateFfi: FfiConverterRustBuffer<CallStateFfi> {
    override fun read(buf: ByteBuffer) = try {
        CallStateFfi.values()[buf.getInt() - 1]
    } catch (e: IndexOutOfBoundsException) {
        throw RuntimeException("invalid enum value, something is very wrong!!", e)
    }

    override fun allocationSize(value: CallStateFfi) = 4UL

    override fun write(value: CallStateFfi, buf: ByteBuffer) {
        buf.putInt(value.ordinal + 1)
    }
