/**
 * ABI-stable error enum для FFI границы. 15 variants — соответствуют
 * [`umbrella_client::ClientError`] 1-к-1, но payload — `String` чтобы
 * flatness гарантировала ABI-стабильность для Swift/Kotlin биндингов.
 *
 * ABI-stable error enum for the FFI boundary. 15 variants matching
 * [`umbrella_client::ClientError`] 1-to-1, with `String` payloads so that
 * flatness guarantees ABI stability across Swift / Kotlin bindings.
 */
sealed class UmbrellaException(message: String): kotlin.Exception(message) {
        
    /**
     * Sub-error из `umbrella-calls` (DTLS fingerprint mismatch, SFrame failure).
     * Sub-error from `umbrella-calls`.
     */
        class Call(message: String) : UmbrellaException(message)
        
    /**
     * Sub-error из `umbrella-backup` (Cloud-wrap, device-transfer).
     * Sub-error from `umbrella-backup`.
     */
        class Backup(message: String) : UmbrellaException(message)
        
    /**
     * Sub-error из `umbrella-mls` (MLS state machine).
     * Sub-error from `umbrella-mls`.
     */
        class Mls(message: String) : UmbrellaException(message)
        
    /**
     * Sub-error из `umbrella-kt` (Key Transparency epoch / proofs).
     * Sub-error from `umbrella-kt`.
     */
        class Kt(message: String) : UmbrellaException(message)
        
    /**
     * Sub-error из `umbrella-oprf` (threshold OPRF — contact discovery).
     * Sub-error from `umbrella-oprf`.
     */
        class Oprf(message: String) : UmbrellaException(message)
        
    /**
     * Sub-error из `umbrella-sealed-sender` (HPKE envelope с anonymous
     * credential).
     * Sub-error from `umbrella-sealed-sender`.
     */
        class SealedSender(message: String) : UmbrellaException(message)
        
    /**
     * Sub-error из `umbrella-identity` (BIP-39 seed, identity / device key).
     * Sub-error from `umbrella-identity`.
     */
        class Identity(message: String) : UmbrellaException(message)
        
    /**
     * Sub-error из `umbrella-padding` (length-hiding buckets).
     * Sub-error from `umbrella-padding`.
     */
        class Padding(message: String) : UmbrellaException(message)
        
    /**
     * Сетевая ошибка (HTTP/2, TURN, ICE binding).
     * Network error.
     */
        class Network(message: String) : UmbrellaException(message)
        
    /**
     * Локальное хранилище — SQLite или native Keychain/Keystore через FFI
     * callback.
     * Local storage — SQLite or native Keychain/Keystore.
     */
        class Storage(message: String) : UmbrellaException(message)
        
    /**
     * Platform attestation — App Attest / Play Integrity. Конкретный
     * underlying-вариант (`AppNotEligible`, `ServiceUnavailable`, …)
     * сериализуется в строку через `Display`.
     * Platform attestation — App Attest / Play Integrity.
     */
        class Attestation(message: String) : UmbrellaException(message)
        
    /**
     * Платформо-специфичная ошибка: Keychain access denied, Secure Enclave
     * unavailable, StrongBox unavailable.
     * Platform-specific error.
     */
        class Platform(message: String) : UmbrellaException(message)
        
    /**
     * Операция отменена пользователем (hang-up, close chat).
     * User-initiated cancellation.
     */
        class Cancelled(message: String) : UmbrellaException(message)
        
    /**
     * Режим-специфичное ограничение. На FFI попадает только если runtime
     * invariant нарушен (compile-fail proof в Rust скрыт от Swift/Kotlin).
     * Mode-specific violation.
     */
        class ModeViolation(message: String) : UmbrellaException(message)
        
    /**
     * Invariant violation — bug в крейте.
     * Invariant violation — a crate bug.
     */
        class Internal(message: String) : UmbrellaException(message)
        

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<UmbrellaException> {
        override fun lift(error_buf: RustBuffer.ByValue): UmbrellaException = FfiConverterTypeUmbrellaError.lift(error_buf)
    }
}

/**
 * @suppress
 */
public object FfiConverterTypeUmbrellaError : FfiConverterRustBuffer<UmbrellaException> {
    override fun read(buf: ByteBuffer): UmbrellaException {
        
            return when(buf.getInt()) {
            1 -> UmbrellaException.Call(FfiConverterString.read(buf))
            2 -> UmbrellaException.Backup(FfiConverterString.read(buf))
            3 -> UmbrellaException.Mls(FfiConverterString.read(buf))
            4 -> UmbrellaException.Kt(FfiConverterString.read(buf))
            5 -> UmbrellaException.Oprf(FfiConverterString.read(buf))
            6 -> UmbrellaException.SealedSender(FfiConverterString.read(buf))
            7 -> UmbrellaException.Identity(FfiConverterString.read(buf))
            8 -> UmbrellaException.Padding(FfiConverterString.read(buf))
            9 -> UmbrellaException.Network(FfiConverterString.read(buf))
            10 -> UmbrellaException.Storage(FfiConverterString.read(buf))
            11 -> UmbrellaException.Attestation(FfiConverterString.read(buf))
            12 -> UmbrellaException.Platform(FfiConverterString.read(buf))
            13 -> UmbrellaException.Cancelled(FfiConverterString.read(buf))
            14 -> UmbrellaException.ModeViolation(FfiConverterString.read(buf))
            15 -> UmbrellaException.Internal(FfiConverterString.read(buf))
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
        
    }

    override fun allocationSize(value: UmbrellaException): ULong {
        return 4UL
    }

    override fun write(value: UmbrellaException, buf: ByteBuffer) {
        when(value) {
            is UmbrellaException.Call -> {
                buf.putInt(1)
                Unit
            }
            is UmbrellaException.Backup -> {
                buf.putInt(2)
                Unit
            }
            is UmbrellaException.Mls -> {
                buf.putInt(3)
                Unit
            }
            is UmbrellaException.Kt -> {
                buf.putInt(4)
                Unit
            }
            is UmbrellaException.Oprf -> {
                buf.putInt(5)
                Unit
            }
            is UmbrellaException.SealedSender -> {
                buf.putInt(6)
                Unit
            }
            is UmbrellaException.Identity -> {
                buf.putInt(7)
                Unit
            }
            is UmbrellaException.Padding -> {
                buf.putInt(8)
                Unit
            }
            is UmbrellaException.Network -> {
                buf.putInt(9)
                Unit
            }
            is UmbrellaException.Storage -> {
                buf.putInt(10)
                Unit
            }
            is UmbrellaException.Attestation -> {
                buf.putInt(11)
                Unit
            }
            is UmbrellaException.Platform -> {
                buf.putInt(12)
                Unit
            }
            is UmbrellaException.Cancelled -> {
                buf.putInt(13)
                Unit
            }
            is UmbrellaException.ModeViolation -> {
                buf.putInt(14)
                Unit
            }
            is UmbrellaException.Internal -> {
                buf.putInt(15)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




/**
 * @suppress
 */
public object FfiConverterOptionalULong: FfiConverterRustBuffer<kotlin.ULong?> {
    override fun read(buf: ByteBuffer): kotlin.ULong? {
        if (buf.get().toInt() == 0) {
            return null
        }
        return FfiConverterULong.read(buf)
    }

    override fun allocationSize(value: kotlin.ULong?): ULong {
        if (value == null) {
            return 1UL
        } else {
            return 1UL + FfiConverterULong.allocationSize(value)
        }
    }

    override fun write(value: kotlin.ULong?, buf: ByteBuffer) {
        if (value == null) {
            buf.put(0)
        } else {
            buf.put(1)
            FfiConverterULong.write(value, buf)
        }
    }
}




